declare @AccountName nvarchar(1024), @AccountName2 nvarchar(1024), @JobName nvarchar(1024), @JobName2 nvarchar(1024)
select @AccountName = ten_tk, @AccountName2 = ten_tk2 from dmtk where tk = @tk
select @JobName = ten_vv, @JobName2 = ten_vv2 from dmvv where ma_vv = @ma_vv

select cast(@ngay1 as smalldatetime) as tu_ngay, cast(@ngay2 as smalldatetime) as den_ngay, @tk as tk, @AccountName as ten_tk,
  @AccountName2 as ten_tk2, @ma_vv as ma_vv, @JobName as ten_vv, @JobName2 as ten_vv2
exec rs_rptJobActivity @ngay1, @ngay2, @ma_kh, @ma_vv, @tk, @ma_dvcs, @vu_viec_con, @@language, @@userID, @@admin
&ReferenceParameters;






      &OutlineEntry;
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  var a = ['tk', 'ma_kh'];
  if (!f._extensions) f.request('GetDefaultValue', 'SetDefaultValue', a);
    else setReferenceValue(f, a);
}

function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      g._hiddenFields = [{Fields: 'ps_no_nt, ps_co_nt, ma_nt, ty_gia', Value: (f.getItemValue('mau_bc')) == '10'}];
      var d1 = f.getItem('ngay1').value, d2 = f.getItem('ngay2').value;
      var account = f.getItemValue('tk'), job = f.getItemValue('ma_vv'), jobname = f.getItemValue('ten_vv%l');
      g._alterTitle = [null, [['%d1', d1, true], ['%d2', d2, true], ['%s1', account, true], ['%s2', job, true], ['%s3', jobname, true]]];
      remove$GridReport$Filter(g);
      break;
    case 'SetDefaultValue':
      f.setItemControlBehavior('ten_tk%l', result[0].Value, null, true);
      if (result[0].Value == '') f.setItemValue('tk', '');
      f.setItemControlBehavior('ten_kh%l', result[1].Value, null, true);
      if (result[1].Value == '') f.setItemValue('ma_kh', '');
      break;
    default:
      break;
  }
}
function setReferenceValue(f, a) {
  for (var i = 0; i < a.length; i++) {
    var r = $func.findField(a[i], f._fields).ItemReference;
    f.setItemValue(r, $func.findMemvar(r, f._extensions).NewValue);
  }
}
/* </flatten> */







declare @c0 nvarchar(1024), @c1 nvarchar(1024)
select @c0 = ten_tk%l from dmtk where tk = @tk
select @c1 = ten_kh%l from dmkh where ma_kh = @ma_kh
select isnull(@c0, '') as c0, isnull(@c1, '') as c1
return





